class Solution {
public:
    int maxFreq(string s, int maxLetters, int minSize, int maxSize) {
        unordered_map<string, int> freq;
        unordered_map<char, int> count;
        int max_freq = 0, unique = 0;
        for (int i = 0; i < s.size(); ++i) {
            count[s[i]]++;
            if (count[s[i]] == 1) unique++;
            if (i >= minSize) {
                if (count[s[i - minSize]]-- == 1) unique--;
                if (unique <= maxLetters) {
                    string substr = s.substr(i - minSize + 1, minSize);
                    max_freq = max(max_freq, ++freq[substr]);
                }
            }
        }
        return max_freq;
    }
};
